s3 = boto3.client("s3")
dynamodb = boto3.resource("dynamodb")
sns = boto3.client("sns")
sqs = boto3.client("sqs")

BUCKET_NAME = os.environ.get("BUCKET_NAME", "")
TABLE_NAME = os.environ.get("TABLE_NAME", "")
TOPIC_ARN = os.environ.get("TOPIC_ARN", "")
QUEUE_URL = os.environ.get("QUEUE_URL", "")


def lambda_handler(event, context):
    try:
        action = event.get("action", "status")

        if action == "status":
            return {
                "statusCode": 200,
                "body": json.dumps(
                    {
                        "message": "Lambda is running",
                        "shared_role_hint": "Use one common IAM role for all microservice Lambdas",
                    }
                ),
            }

        if action == "s3_put":
            key = event["key"]
            body = event.get("body", "")
            s3.put_object(Bucket=BUCKET_NAME, Key=key, Body=body.encode("utf-8"))
            return {"statusCode": 200, "body": json.dumps({"message": "S3 object stored", "key": key})}

        if action == "ddb_put":
            table = dynamodb.Table(TABLE_NAME)
            item = event["item"]
            table.put_item(Item=item)
            return {"statusCode": 200, "body": json.dumps({"message": "DynamoDB item stored"})}

        if action == "sns_publish":
            message = event["message"]
            response = sns.publish(TopicArn=TOPIC_ARN, Message=message)
            return {
                "statusCode": 200,
                "body": json.dumps({"message": "SNS message published", "message_id": response["MessageId"]}),
            }

        if action == "sqs_send":
            message = event["message"]
            response = sqs.send_message(QueueUrl=QUEUE_URL, MessageBody=message)
            return {
                "statusCode": 200,
                "body": json.dumps({"message": "SQS message sent", "message_id": response["MessageId"]}),
            }

        return {"statusCode": 400, "body": json.dumps({"error": f"Unknown action: {action}"})}

    except KeyError as exc:
        return {"statusCode": 400, "body": json.dumps({"error": f"Missing required field: {str(exc)}"})}
    except ClientError as exc:
        return {"statusCode": 500, "body": json.dumps({"error": "AWS client error", "details": str(exc)})}
    except Exception as exc:
        return {"statusCode": 500, "body": json.dumps({"error": "Unexpected error", "details": str(exc)})}